class Solution {
    public int findIntegers(int n) {
        int MOD = (int)1e9 + 7;
        int a = 1, b = 1, p = 1, q = 1;
        for (int i = 0; (1 << i) <= n; i++) {
            p = (p * 2) % MOD;
            q = (q * 2 + (i > 0 ? a : 0)) % MOD;
            a = b;
            b = q;
        }
        return q;
    }
}
